{"code": "quote_items = [
    {"TotalPrice": 2279.9525, "Discount": 5.0},
    {"TotalPrice": 2379.932, "Discount": 15.0},
    {"TotalPrice": 4499.91, "Discount": 10.0},
    {"TotalPrice": 2260.9335, "Discount": 5.0}
]

